 70→    selectedType,
 71→    dispatch: editorDispatch,
 72→  } = useEditor();
 73→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 74→  const {
 75→    canCopySelection,
 76→    canPaste,
 77→    copySelection,
 78→    cutSelection,
 79→    beginPaste,
 80→  } = usePlanClipboardController();
 81→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'floor';
 82→  const isRoofPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'roof';
