148→    editorDispatch({ type: 'DESELECT' });
149→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
150→  }, [canUndo, dispatch, editorDispatch]);
151→
152→  const handleRedo = useCallback(() => {
