154→    dispatch({ type: 'REDO' });
155→    editorDispatch({ type: 'DESELECT' });
156→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
157→  }, [canRedo, dispatch, editorDispatch]);
158→
159→  const handleDetectRooms = () => {
160→    const floor = project.floors.find(f => f.id === activeFloorId);
161→    if (!floor || floor.walls.length < 3) {
