192→        return;
193→      }
194→      handleUndo();
195→    };
196→
197→    window.addEventListener('keydown', handleKeyDown);
198→    return () => window.removeEventListener('keydown', handleKeyDown);
199→  }, [handleRedo, handleUndo]);
