343→export function TrussInstanceProperties({
344→  project,
345→  trussSystem,
346→  trussInstance,
347→  dispatch,
348→  u,
349→}) {
350→  const trussTypes = getDefaultTrussTypes();
351→  const trussType = resolveTrussType(trussInstance.trussTypeId, trussTypes);
352→  const floor = (project?.floors || []).find((entry) => entry.id === trussSystem.floorId) || null;
353→  const beamSupport = trussInstance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
354→    ? deriveBeamSupportedInstanceGeometry(trussInstance, floor)
355→    : null;
356→  const supportLength = beamSupport?.valid
357→    ? beamSupport.supportLength
358→    : distance(trussInstance.startPoint, trussInstance.endPoint);
359→  const supportSpan = beamSupport?.valid ? beamSupport.span : null;
360→  const countLimit = beamSupport?.valid
361→    ? beamSupport.countLimit
362→    : trussInstance.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
363→      ? getBeamSupportCountLimit(supportLength, trussInstance.spacing)
364→      : null;
365→  const alignmentOffset = beamSupport?.valid
366→    ? beamSupport.effectiveOffset
