114→export function RoofSystemProperties({
115→  project,
116→  roofSystem,
117→  dispatch,
118→  editorDispatch,
119→  u,
120→  phases = [],
121→  isHiddenByPhase = false,
122→  activePhaseName = null,
123→  phaseViewMode = 'all',
