125→  const updateRoof = (updates) => {
126→    dispatch({ type: 'ROOF_UPDATE', roofSystem: { id: roofSystem.id, ...updates } });
127→  };
128→  const trussSystems = project.trussSystems || [];
129→  const attachableTrussSystems = getAttachableRoofTrussSystems(project);
130→  const attachedTruss = trussSystems.find((entry) => entry.id === roofSystem.trussAttachmentId) || null;
131→  const attachedTrussRoofType = attachedTruss ? resolveTrussSystemRoofAttachmentType(attachedTruss) : null;
132→  const geometry = buildRoofPlanGeometry(roofSystem);
133→  const roofPlaneGeometry = buildRoofPlaneGeometry(roofSystem);
134→  const schedule = buildRoofScheduleSummary(roofSystem);
135→  const roofType = roofSystem.roofType || 'flat';
136→  const pitch = roofSystem.pitch || {};
137→  const pitchAngle = roofPitchDirectionToAngle(pitch.direction);
138→  const customPlaneCount = (roofSystem.roofPlanes || []).length;
139→  const customSeamCount = (roofPlaneGeometry.roofEdges || []).filter((edge) => !edge.isPerimeter).length;
140→  const isAttachedToTruss = Boolean(roofSystem.trussAttachmentId);
141→  const followsAttachedTrussBoundary = isAttachedToTruss;
142→  const followsAttachedTrussPitch = Boolean(isAttachedToTruss && roofType !== 'flat' && roofType !== 'custom');
143→
144→  const addRoofPlane = () => {
145→    const nextPlane = createRoofPlane(
146→      roofPlaneGeometry.roofOutline?.length
147→        ? roofPlaneGeometry.roofOutline
148→        : (roofSystem.boundaryPolygon || []),
149→      {
150→        name: `Plane ${customPlaneCount + 1}`,
151→        baseElevation: roofSystem.baseElevation ?? 0,
152→        slope: pitch.slope || 20,
153→        slopeDirection: pitch.direction,
154→      }
155→    );
156→
157→    dispatch({ type: 'ROOF_PLANE_ADD', roofPlane: nextPlane });
158→    editorDispatch({ type: 'SELECT_OBJECT', id: nextPlane.id, objectType: 'roofPlane' });
159→  };
160→
161→  const updatePitch = (updates) => {
162→    updateRoof({
163→      pitch: {
164→        ...pitch,
165→        ...updates,
166→      },
167→    });
168→  };
169→
170→  return (
171→    <div>
172→      <div className={styles.title}>Roof</div>
173→      {isHiddenByPhase && (
174→        <div className={styles.drawingHint}>
