185→        phases={phases}
186→        onChange={(value) => updateRoof({ phaseId: value })}
187→      />
188→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
189→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Truss Link</label>
190→        <select
191→          value={roofSystem.trussAttachmentId || ''}
192→          onChange={(e) => updateRoof({ trussAttachmentId: e.target.value || null })}
193→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px', background: 'var(--color-surface-elevated)' }}
194→        >
