405→export function ParapetProperties({ parapet, roofSystem, dispatch, u }) {
406→  const updateParapet = (updates) => {
407→    dispatch({ type: 'PARAPET_UPDATE', parapet: { id: parapet.id, ...updates } });
408→  };
409→  const resolved = resolveParapetLine(parapet, roofSystem) || {
410→    startPoint: parapet.startPoint,
411→    endPoint: parapet.endPoint,
412→  };
413→  const roofEdges = buildRoofBoundaryEdges(roofSystem);
414→  const attachedEdge = parapet.attachment?.type === 'roof_edge'
415→    ? roofEdges.find((edge) => edge.index === parapet.attachment.edgeIndex)
416→    : null;
417→
418→  const attachToNearestRoofEdge = () => {
419→    const attachment = buildParapetEdgeAttachmentForPoints(roofSystem, resolved.startPoint, resolved.endPoint);
420→    if (!attachment) return;
421→
422→    updateParapet({
423→      attachment,
424→      startPoint: resolved.startPoint,
425→      endPoint: resolved.endPoint,
426→    });
427→  };
428→
429→  const detachFromEdge = () => {
430→    updateParapet({
431→      attachment: null,
432→      startPoint: resolved.startPoint,
433→      endPoint: resolved.endPoint,
434→    });
435→  };
436→
437→  return (
438→    <div>
439→      <div className={styles.title}>Parapet</div>
440→      <InputField label="Name" value={parapet.name || ''} onChange={(value) => updateParapet({ name: value })} />
441→      <InputField label="Mode" value={parapet.attachment?.type === 'roof_edge' ? 'Roof Edge' : 'Free'} readOnly />
442→      {attachedEdge ? (
443→        <>
444→          <InputField label="Edge" value={attachedEdge.index + 1} readOnly />
445→          <InputField label="Edge Role" value={attachedEdge.parapetPlacement?.label || 'Edge'} readOnly />
446→          <InputField label="Edge Length" suffix={u.suffix} value={u.toDisplay(attachedEdge.length)} readOnly />
447→        </>
448→      ) : null}
449→      <div className={styles.subtitle}>Start Point</div>
450→      <InputField
451→        label="X"
452→        type="number"
453→        suffix={u.suffix}
454→        value={u.toDisplay(resolved.startPoint.x)}
455→        readOnly={Boolean(attachedEdge)}
456→        onChange={(value) => updateParapet({ attachment: null, startPoint: { ...resolved.startPoint, x: u.fromDisplay(value) } })}
457→      />
458→      <InputField
459→        label="Y"
460→        type="number"
461→        suffix={u.suffix}
462→        value={u.toDisplay(resolved.startPoint.y)}
463→        readOnly={Boolean(attachedEdge)}
464→        onChange={(value) => updateParapet({ attachment: null, startPoint: { ...resolved.startPoint, y: u.fromDisplay(value) } })}
465→      />
466→      <div className={styles.subtitle}>End Point</div>
467→      <InputField
468→        label="X"
469→        type="number"
470→        suffix={u.suffix}
471→        value={u.toDisplay(resolved.endPoint.x)}
472→        readOnly={Boolean(attachedEdge)}
473→        onChange={(value) => updateParapet({ attachment: null, endPoint: { ...resolved.endPoint, x: u.fromDisplay(value) } })}
474→      />
475→      <InputField
476→        label="Y"
477→        type="number"
478→        suffix={u.suffix}
479→        value={u.toDisplay(resolved.endPoint.y)}
480→        readOnly={Boolean(attachedEdge)}
481→        onChange={(value) => updateParapet({ attachment: null, endPoint: { ...resolved.endPoint, y: u.fromDisplay(value) } })}
482→      />
483→      <div className={styles.subtitle}>Properties</div>
484→      <InputField label="Length" suffix={u.suffix} value={u.toDisplay(wallLength({ start: resolved.startPoint, end: resolved.endPoint }))} readOnly />
485→      <InputField label="Height" type="number" suffix={u.suffix} step={u.step(10)} value={u.toDisplay(parapet.height || 0)} onChange={(value) => updateParapet({ height: Math.max(50, u.fromDisplay(value)) })} />
486→      <InputField label="Thickness" type="number" suffix={u.suffix} step={u.step(10)} value={u.toDisplay(parapet.thickness || 0)} onChange={(value) => updateParapet({ thickness: Math.max(20, u.fromDisplay(value)) })} />
487→      {attachedEdge ? (
488→        <>
489→          {!attachedEdge.parapetPlacement?.allowed && (
490→            <div className={styles.drawingHint}>
491→              This parapet is attached to an edge that is not recommended for the current roof type.
492→            </div>
493→          )}
494→          <button
495→            className={styles.actionBtn}
496→            onClick={() => updateParapet({
497→              attachment: {
498→                ...parapet.attachment,
499→                startOffset: 0,
500→                endOffset: attachedEdge.length,
501→              },
502→            })}
503→          >
504→            Follow full edge
505→          </button>
506→          <button className={styles.actionBtn} onClick={detachFromEdge}>
507→            Detach from edge
508→          </button>
509→        </>
510→      ) : (
511→        <>
512→          <button className={styles.actionBtn} onClick={attachToNearestRoofEdge}>
513→            Attach to nearest valid roof edge
514→          </button>
515→          <div className={styles.drawingHint}>
516→            {parapetPlacementHint(roofSystem)}
517→          </div>
518→        </>
519→      )}
520→    </div>
521→  );
522→}
